# Problem: Create a Pydantic model for user registration with custom validation
# rules for username format, email format, password strength, age range, and full_name.
#
# Approach:
# - Use Pydantic v2 BaseModel with @field_validator decorators for each field.
# - Username: regex-style checks (length, alphanumeric+underscore, starts with letter).
# - Email: string checks for exactly one @, domain with dot, no spaces.
# - Password: length + character class membership checks.
# - Age: simple range check.
# - Full name: strip whitespace, check non-empty.
#
# Time complexity: O(n) per field where n is the string length.
# Space complexity: O(1) additional space per validation.
#
# Key steps:
# 1. Define field validators that raise ValueError on invalid input.
# 2. For full_name, strip whitespace and return the cleaned value.
# 3. Implement validate_user to catch ValidationError and return a tuple.

from pydantic import BaseModel, field_validator, ValidationError


class UserRegistration(BaseModel):
    username: str
    email: str
    password: str
    age: int
    full_name: str

    @field_validator("username")
    @classmethod
    def validate_username(cls, v: str) -> str:
        if len(v) < 3 or len(v) > 20:
            raise ValueError("Username must be between 3 and 20 characters")
        if not v[0].isalpha():
            raise ValueError("Username must start with a letter")
        if not all(c.isalnum() or c == "_" for c in v):
            raise ValueError("Username must contain only alphanumeric characters and underscores")
        return v

    @field_validator("email")
    @classmethod
    def validate_email(cls, v: str) -> str:
        if " " in v:
            raise ValueError("Email must not contain spaces")
        parts = v.split("@")
        if len(parts) != 2:
            raise ValueError("Email must contain exactly one @")
        local, domain = parts
        if not local:
            raise ValueError("Email local part must not be empty")
        if "." not in domain or domain.startswith(".") or domain.endswith("."):
            raise ValueError("Email domain must contain at least one dot and be valid")
        return v

    @field_validator("password")
    @classmethod
    def validate_password(cls, v: str) -> str:
        if len(v) < 8:
            raise ValueError("Password must be at least 8 characters long")
        if not any(c.isupper() for c in v):
            raise ValueError("Password must contain at least one uppercase letter")
        if not any(c.islower() for c in v):
            raise ValueError("Password must contain at least one lowercase letter")
        if not any(c.isdigit() for c in v):
            raise ValueError("Password must contain at least one digit")
        special = set("!@#$%^&*")
        if not any(c in special for c in v):
            raise ValueError("Password must contain at least one special character (!@#$%^&*)")
        return v

    @field_validator("age")
    @classmethod
    def validate_age(cls, v: int) -> int:
        if v < 18 or v > 120:
            raise ValueError("Age must be between 18 and 120")
        return v

    @field_validator("full_name")
    @classmethod
    def validate_full_name(cls, v: str) -> str:
        v = v.strip()  # auto-strip leading/trailing whitespace
        if not v:
            raise ValueError("Full name must not be empty")
        return v


def validate_user(data: dict) -> tuple[bool, str | object]:
    """Attempt to create a UserRegistration from the given dict.
    Returns (True, user_instance) on success, or (False, error_message) on failure.
    """
    try:
        user = UserRegistration(**data)
        return (True, user)
    except ValidationError as e:
        return (False, f"Validation error: {e}")
